Constante Valor Descricao <code>MYSQL_OK</code> 0 Sem erro <code>MYSQL_ERROR_CONNECTION_FAILED</code> 1 Falha na conexao <code>MYSQL_ERROR_INVALID_OPTIONS</code> 2 Handle de options invalido <code>MYSQL_ERROR_INVALID_CONNECTION</code> 3 Conexao invalida <code>MYSQL_ERROR_PING_FAILED</code> 4 Ping falhou <code>MYSQL_ERROR_QUERY_FAILED</code> 5 Falha na query <code>MYSQL_ERROR_NO_CACHE_ACTIVE</code> 6 Nenhum cache ativo <code>MYSQL_ERROR_INVALID_ORM</code> 7 ORM invalido <code>MYSQL_ERROR_ORM_KEY_NOT_SET</code> 8 Chave ORM nao definida <pre><code>gMysql = mysql_connect("127.0.0.1", "root", "senha", "samp_db");

if (mysql_errno()) {
    printf("Erro de conexao: %d", mysql_errno());
    return 1;
}
</code></pre>

R41-4 mysql_samp Significado <code>"i"</code> <code>"d"</code> ou <code>"i"</code> Inteiro (ambos funcionam no mysql_samp) <code>"f"</code> <code>"f"</code> Float (igual) <code>"s"</code> <code>"s"</code> String (igual) <p>Nota: o mysql_samp aceita tanto <code>"d"</code> quanto <code>"i"</code> para inteiros. Se voce ja usa <code>"i"</code>, nao precisa mudar.</p> <pre><code>// R41-4
mysql_tquery(gMysql, query, "OnLoad", "i", playerid);

// mysql_samp (ambos funcionam)
mysql_query(gMysql, query, "OnLoad", "d", playerid);
mysql_query(gMysql, query, "OnLoad", "i", playerid);
</code></pre>

R41-4 mysql_samp <code>MySQL:mysql_connect(host, user, pass, db, MySQLOpt:opt)</code> <code>mysql_connect(host, user, pass, db, options)</code> <code>MySQLOpt:mysql_init_options()</code> <code>mysql_options_new()</code> <code>mysql_set_option(MySQLOpt:opt, type, ...)</code> <code>mysql_options_set_int(opt, type, val)</code> / <code>mysql_options_set_str(opt, type, val[])</code> <code>mysql_escape_string(src, dest, max_len, MySQL:handle)</code> <code>mysql_escape_string(src, dest, max_len)</code> <code>mysql_stat(dest, max_len, MySQL:handle)</code> <code>mysql_status(connId, dest, max_len)</code> <code>mysql_error(dest, max_len, MySQL:handle)</code> <code>mysql_error(connId, dest, max_len)</code> <code>mysql_errno(MySQL:handle)</code> <code>mysql_errno(connId)</code> <code>mysql_set_charset(charset, MySQL:handle)</code> <code>mysql_set_charset(connId, charset)</code> <code>mysql_get_charset(dest, max_len, MySQL:handle)</code> <code>mysql_get_charset(connId, dest, max_len)</code> <code>mysql_close(MySQL:handle)</code> <code>mysql_close(connId)</code> <code>mysql_unprocessed_queries(MySQL:handle)</code> <code>mysql_unprocessed_queries()</code> (nao existe) <code>mysql_log(level)</code> <p>Diferenca de estilo: no R41-4, o handle e o ultimo parametro (opcional, default <code>MySQL:1</code>). No mysql_samp, o connId e o primeiro parametro.</p> <p>Porta: no R41-4, usa-se <code>mysql_set_option(opt, SERVER_PORT, 3307)</code>. No mysql_samp, usa-se <code>mysql_options_set_int(opt, MYSQL_OPT_PORT, 3307)</code>.</p> <pre><code>// R41-4
new MySQLOpt:opt = mysql_init_options();
mysql_set_option(opt, SERVER_PORT, 3307);
new MySQL:gMysql = mysql_connect("127.0.0.1", "root", "pass", "db", opt);

// mysql_samp
new opt = mysql_options_new();
mysql_options_set_int(opt, MYSQL_OPT_PORT, 3307);
new gMysql = mysql_connect("127.0.0.1", "root", "pass", "db", opt);

// mysql_samp (porta padrao 3306 — sem options)
new gMysql = mysql_connect("127.0.0.1", "root", "pass", "db");
</code></pre>

R41-4 mysql_samp <code>cache_get_row_count(&amp;dest)</code> <code>cache_get_row_count()</code> retorna <code>int</code> <code>cache_get_field_count(&amp;dest)</code> <code>cache_get_field_count()</code> retorna <code>int</code> <code>cache_num_rows()</code> (stock wrapper) <code>cache_get_row_count()</code> <code>cache_num_fields()</code> (stock wrapper) <code>cache_get_field_count()</code> <pre><code>// R41-4
new rows;
cache_get_row_count(rows);
// ou
new rows = cache_num_rows();

// mysql_samp
new rows = cache_get_row_count();
</code></pre>

R41-4 mysql_samp <code>cache_get_value_index(row, col, dest[], max_len)</code> <code>cache_get_value_index(row, col, dest[], max_len)</code> (igual) <code>cache_get_value_index_int(row, col, &amp;dest)</code> <code>cache_get_value_index_int(row, col)</code> retorna <code>int</code> <code>cache_get_value_index_float(row, col, &amp;Float:dest)</code> <code>cache_get_value_index_float(row, col)</code> retorna <code>Float</code> <pre><code>// R41-4
new score;
cache_get_value_index_int(0, 2, score);

// mysql_samp
new score = cache_get_value_index_int(0, 2);
</code></pre>

R41-4 mysql_samp <code>cache_get_value_name(row, col_name, dest[], max_len)</code> <code>cache_get_value_name(row, col_name, dest[], max_len)</code> (igual) <code>cache_get_value_name_int(row, col_name, &amp;dest)</code> <code>cache_get_value_name_int(row, col_name)</code> retorna <code>int</code> <code>cache_get_value_name_float(row, col_name, &amp;Float:dest)</code> <code>cache_get_value_name_float(row, col_name)</code> retorna <code>Float</code> <pre><code>// R41-4
new score;
cache_get_value_name_int(0, "score", score);
new Float:pos_x;
cache_get_value_name_float(0, "pos_x", pos_x);

// mysql_samp
new score = cache_get_value_name_int(0, "score");
new Float:pos_x = cache_get_value_name_float(0, "pos_x");
</code></pre>

R41-4 mysql_samp <code>cache_is_value_index_null(row, col, &amp;bool:dest)</code> <code>cache_is_value_index_null(row, col)</code> retorna <code>bool</code> <code>cache_is_value_name_null(row, col_name, &amp;bool:dest)</code> <code>cache_is_value_name_null(row, col_name)</code> retorna <code>bool</code> <pre><code>// R41-4
new bool:is_null;
cache_is_value_name_null(0, "email", is_null);

// mysql_samp
new bool:is_null = cache_is_value_name_null(0, "email");
</code></pre>

R41-4 mysql_samp <code>mysql_log(E_LOGLEVEL:level)</code> <code>mysql_log(level)</code> Bitflags: DEBUG=1, INFO=2, WARNING=4, ERROR=8 Sequencial: NONE=0, ERROR=1, WARNING=2, INFO=3, ALL=4 <pre><code>// R41-4
mysql_log(ERROR | WARNING);

// mysql_samp
mysql_log(MYSQL_LOG_WARNING); // inclui ERROR e WARNING
</code></pre>
